import * as React from "react";
import { RouteComponentProps, withRouter } from "react-router";
import { connect } from "react-redux";
import { CSSProperties } from "react";
import { Tooltip, Tree, Icon } from 'antd';
import { updateMaxWidget, updateWidget, updateActivePanel } from "../../actions/settingActions";
import { Editor_Panel_NavPanel } from "../../constants/EditorPanelNames";
import { formatMessage } from "../../AppRouter";
import { IRepo } from "../../interfaces/IAccount";
import { getIconNameByLanguage } from "../../utils/getIconByLanguage";

const { TreeNode } = Tree;
const zanejs = (window as any).zanejs;

interface IState {
    treeData: any;
}

interface IProps extends RouteComponentProps<any> {
    leftWidget: string | null;
    maxWidget: number;
    activePanel: string | null | undefined;
    repos: IRepo[];
    updateWidget: Function;
    updateMaxWidget: Function;
    updateActivePanel: Function;
}

const mapStateToProps = (state: any) => {
    return {
        repos: state.account.repos,
        leftWidget: state.setting.leftWidget,
        maxWidget: state.setting.maxWidget,
        activePanel: state.setting.activePanel,
    }
};

const mapDispatchTpProps = {
    updateWidget,
    updateMaxWidget,
    updateActivePanel,
};

const baseCSSProperties: CSSProperties = {
    position: 'absolute',
    overflow: 'hidden',
    left: 0,
    top: 0,
    right: 0,
    bottom: 0
};

class WorkspaceNavPanel extends React.Component<IProps, IState> {

    constructor(props: IProps) {
        super(props);
        this.state = {
            treeData: []
        };
    }

    componentWillReceiveProps(nextProps: IProps) {
        if (this.props.repos != nextProps.repos) {
            this.generateTreeData(nextProps.repos);
        }
    }

    componentDidMount() {
        this.generateTreeData(this.props.repos);
    }

    onLoadData = (treeNode: any): PromiseLike<void> => {
        return new Promise((resolve: Function) => {
            if (treeNode.props.children) {
                resolve();
                return;
            }
        });
    };

    generateTreeItemIcon = (props: any) => {
        return <img src={props.expanded ? props.openIcon : props.closeIcon} />;
    };

    generateTreeData = (repos: IRepo[]) => {
        const treeData: any = [];
        if (repos) {
            repos.map((item: IRepo, index: number) => {
                const iconName = getIconNameByLanguage(item.language);
                treeData.push({
                    title: item.name,
                    closeIcon: `${process.env.PUBLIC_URL}/assets/svg/${iconName}.svg`,
                    openIcon: `${process.env.PUBLIC_URL}/assets/svg/${iconName}-open.svg`,
                    icon: this.generateTreeItemIcon,
                    key: `${index}`
                });
            });
        }
        this.setState({treeData});
    };

    generateWorkspaceExplorer = () => {
        
        return (
            <div className="workspaceExplorer">
                <div className="header">
                    <div className="toolbar">
                        <div style={{...baseCSSProperties, right: undefined, width: 2}} />
                        <div style={{...baseCSSProperties, right: undefined, left: 5, width: 200}}>
                            {formatMessage({id: 'app.workspaceExplorer'})}
                        </div>
                        
                    </div>
                </div>
                <div className="body">
                    {
                        this.state.treeData.length > 0 
                        ? (
                            <Tree  
                                showLine={true}
                                showIcon={true}
                                className="myTree"
                                switcherIcon={<Icon type="down" />}
                                loadData={this.onLoadData}>
                                {this.renderTreeNodes(this.state.treeData)}
                            </Tree>
                        ) 
                        : (
                            <p>暂无内容</p>
                        )
                    }
                </div>
            </div>
        );
    };

    renderTreeNodes = (data: any) => {
        return data.map((item: any) => {
            if (item.children) {
              return (
                <TreeNode title={item.title} key={item.key} dataRef={item}>
                    {this.renderTreeNodes(item.children)}
                </TreeNode>
              );
            }
            return <TreeNode key={item.key} {...item} dataRef={item} />;
        });
    };

    render() {
        return (
            <div className="navPanel" onClick={() => this.props.updateActivePanel(Editor_Panel_NavPanel)}>
                <div className="content">
                    {this.generateWorkspaceExplorer()}
                </div>
            </div>
        )
    }
}
export default withRouter(connect(mapStateToProps, mapDispatchTpProps)(WorkspaceNavPanel));