import * as React from "react";
import { RouteComponentProps, withRouter } from "react-router";
import { connect } from "react-redux";

const CodeMirror = (window as any).CodeMirror;
const IS_MOBILE = typeof navigator === 'undefined' || (
    navigator.userAgent.match(/Android/i)
      || navigator.userAgent.match(/webOS/i)
      || navigator.userAgent.match(/iPhone/i)
      || navigator.userAgent.match(/iPad/i)
      || navigator.userAgent.match(/iPod/i)
      || navigator.userAgent.match(/BlackBerry/i)
      || navigator.userAgent.match(/Windows Phone/i)
);

interface IState {
    isControlled: boolean;
}

interface IProps extends RouteComponentProps<any> {
    value?: string;
    defaultValue?: string;
    mode?: string;
    theme?: string;
    readOnly?: boolean;
    textAreaClassName?: string;
    onChange?: any;
    forceTextArea?: boolean;
}

const mapStateToProps = (state: any) => {
    return {
        
    }
};

const mapDispatchTpProps = {

};

class CodeMirrorEditor extends React.Component<IProps, IState> {

    private editorRef: any;
    private editor: any;

    constructor(props: IProps) {
        super(props);
        this.state = {
            isControlled: !!this.props.value
        };
    }

    componentDidMount() {
        const isTextArea = this.props.forceTextArea || IS_MOBILE;
        if (!isTextArea) {
            this.editor = CodeMirror.fromTextArea(this.editorRef, {
                mode: this.props.mode,
                theme: this.props.theme,
                lineNumbers: true,
                lineWrapping: true,
                foldGutter: true,
                gutters: ["CodeMirror-linenumbers", "CodeMirror-foldgutter"]
            });
            this.editor.on('change', this.handleChange);
        }
    }

    componentDidUpdate() {
        if (!this.editor) {
            return
        }
    
        if (this.props.value) {
            const currentValue = this.editor.getValue();
            if (currentValue !== this.props.value) {
                this.editor.setValue(this.props.value);
            }
        }
    }

    handleChange = () => {
        if (!this.editor) {
            return;
        }
    
        const value = this.editor.getValue()
        if (value === this.props.value) {
            return;
        }
    
        if (this.props.onChange) {
            this.props.onChange({target: {value: value}});
        }
    }

    render() {
        return <textarea 
            ref={value => this.editorRef=value}
            value={this.props.value}
            defaultValue={this.props.defaultValue}
            className={this.props.textAreaClassName}
            onChange={this.props.onChange} />
    }
}
export default withRouter(connect(mapStateToProps, mapDispatchTpProps)(CodeMirrorEditor));