import * as React from "react";
import { RouteComponentProps, withRouter } from "react-router";
import { connect } from "react-redux";
import { formatMessage } from "../../AppRouter";
import { updateModalName, updateFile } from "../../actions/editorActions";
import { updateBlogNavTreeConfig } from "../../actions/blogActions";
import { createOrUpdateFileContents, getRepoContents } from "../../actions/githubActions";
import {
    Modal_Audio_Convert, 
    Modal_Video_Convert, 
    Modal_Images_To_Ico 
} from './../../constants/ModalNames';
import { IUserInfo } from "../../interfaces/IAccount";
import { IOpenFiles } from "../../interfaces/IOpenfile";
import { generateIcon } from "../../utils/generateIcon";
import { IPanes } from "../../interfaces/IPane";
import { ISite } from "../../interfaces/ISetting";
import { IBlogNav } from "../../interfaces/IBlog";
import { CONFIG_BLOG_URL } from "../../constants/Github";

interface IState {

}

interface IProps extends RouteComponentProps<any> {
    userInfo: IUserInfo;
    openfiles: IOpenFiles;
    activePane: string|undefined;
    blogNavTreeData: IBlogNav[];
    blogSha: string;
    navSelectedKey: string;
    panes: IPanes;
    siteInfo: ISite;
    updateModalName: Function;
    updateFile: Function;
    updateBlogNavTreeConfig: Function;
    createOrUpdateFileContents: Function;
    getRepoContents: Function;
}

const mapStateToProps = (state: any) => {
    return {
        activePane: state.editor.activePane,
        panes: state.panes,
        userInfo: state.account.userInfo,
        siteInfo: state.setting.siteInfo,
        blogNavTreeData: state.blog.navTreeData,
        blogSha: state.blog.sha,
        navSelectedKey: state.blog.navSelectedKey,
        openfiles: state.openfiles
    }
};

const mapDispatchTpProps = {
    updateModalName,
    updateFile,
    updateBlogNavTreeConfig,
    createOrUpdateFileContents,
    getRepoContents
};

const groupTools1 = [
    {
        "label": "app.audioConvert",
        "icon": "assets/svg/toolbar-sound.svg",
        "action": "audioConvert"
    },
    {
        "label": "app.videoConvert",
        "icon": "assets/svg/toolbar-video.svg",
        "action": "videoConvert"
    },
    {
        "label": "app.imagesToIco",
        "icon": "assets/svg/toolbar-to-ico.svg",
        "action": "imagesToIco"
    }
];

class ToolPanel extends React.Component<IProps, IState> {

    doAction = (action: string) => {
        switch (action) {
            case 'audioConvert':
                this.props.updateModalName(Modal_Audio_Convert);
                break;
            case 'videoConvert':
                this.props.updateModalName(Modal_Video_Convert);
                break;
            case 'imagesToIco':
                this.props.updateModalName(Modal_Images_To_Ico);
                break;
        }
    };

    handleSaveFile = () => {
        const data = [...this.props.blogNavTreeData];
        const activePane = this.props.activePane ? this.props.panes[this.props.activePane] : null;
        if (activePane && activePane.activeFile) {
            const activeFile = this.props.openfiles[activePane.activeFile];
            if (activeFile && activeFile.needUpload) {
                const win = window as any;
                const updateFile = () => {
                    this.props.createOrUpdateFileContents(
                        this.props.siteInfo.repo, 
                        activeFile.path, 
                        activeFile.content ? win.btoa(unescape(encodeURIComponent(activeFile.content))) : '', 
                        activeFile.sha, 
                        'master', 
                        (res: any) => {
                            if (res && res.content && res.content.sha) {
                                this.updateBlogDataFileSha(data, activeFile.sha, res.content.sha);
                                this.updateBlogData(data);
                                activeFile.needUpload = false;
                                activeFile.sha = res.content.sha;
                                this.props.updateFile(activeFile);
                            }
                        },
                        (res: any) => {
                            if (res && res.code == 409) {
                                this.props.getRepoContents(
                                    this.props.siteInfo.repo, 
                                    activeFile.path, 
                                    'master', 
                                    ($res: any) => {
                                        activeFile.sha = $res.sha;
                                        this.props.updateFile(activeFile);
                                        updateFile();
                                    }
                                );
                            }
                        }
                    );
                }
                updateFile();
            }
        }
    };

    handleSaveAllFile = () => {
        const win = window as any;
        const data = [...this.props.blogNavTreeData];
        const needUploadFiles: any[] = [];
        Object.keys(this.props.openfiles).map(key => {
            const $openFile = this.props.openfiles[key];
            if ($openFile.needUpload) {
                needUploadFiles.push($openFile);
            }
        });
        const loop = () => {
            const $openFile = needUploadFiles.shift();
            if ($openFile) {
                this.props.createOrUpdateFileContents(
                    this.props.siteInfo.repo, 
                    $openFile.path, 
                    $openFile.content ? win.btoa(unescape(encodeURIComponent($openFile.content))) : '', 
                    $openFile.sha, 
                    'master', 
                    (res: any) => {
                        if (res && res.content && res.content.sha) {
                            this.updateBlogDataFileSha(data, $openFile.sha, res.content.sha);
                            $openFile.needUpload = false;
                            $openFile.sha = res.content.sha;
                            this.props.updateFile($openFile);
                        }
                        loop();
                    },
                    (res: any) => {
                        if (res && res.code == 409) {
                            this.props.getRepoContents(
                                this.props.siteInfo.repo, 
                                $openFile.path, 
                                'master', 
                                ($res: any) => {
                                    $openFile.sha = $res.sha;
                                    needUploadFiles.push($openFile);
                                    this.props.updateFile($openFile);
                                    loop();
                                }
                            );
                        }
                        loop();
                    }
                );
            } else {
                this.updateBlogData(data);
            }
        }
        loop();
    };

    updateBlogDataFileSha = (data: any, oldSha: string|undefined, newSha: string,  callback: Function|null = null) => {
        const loop = (data: any) => data.map((item: any, index: number, arr: any[]) => {
            if (item.sha == oldSha) {
                item.sha = newSha;
            } else if (item.children) {
                loop(item.children);
            }
        });
        loop(data);
        if (callback) {
            callback(data);
        }
    };

    updateBlogData = (data: any, callback: Function|null = null) => {
        const win = window as any;
        const configDataToStr = unescape(encodeURIComponent(JSON.stringify(data)));
        const configDataBase64Str = win.btoa(configDataToStr);
        this.props.createOrUpdateFileContents(
            this.props.siteInfo.repo, 
            CONFIG_BLOG_URL, 
            configDataBase64Str, 
            this.props.blogSha, 
            'master', 
            (res: any) => {
                if (res && res.content && res.content.sha) {
                    this.props.updateBlogNavTreeConfig({
                        navTreeData: data,
                        sha: res.content.sha
                    });
                    callback && callback(true);
                } else {
                    callback && callback(false);
                }
            }
        );
    };

    render() {
        let needUpload = false;
        Object.keys(this.props.openfiles).map(key => {
            const $openFile = this.props.openfiles[key];
            if ($openFile.needUpload) {
                needUpload = true;
            }
        });
        return (
            <div className="toolbarPanel">
                <div className="content">
                    <div 
                        className="button-group" 
                        style={{
                            height: 25,
                            marginTop: 5,
                            marginLeft: 20, 
                            marginRight: 5, 
                            padding: 0
                        }}>
                        {
                            groupTools1.map((item, index) => {
                                return (
                                    <div
                                        key={index}
                                        onClick={(e) => this.doAction(item.action)}>
                                        {generateIcon(item.icon) }
						                <span>{formatMessage({id: item.label}) }</span>
                                    </div> 
                                )
                            })
                        }
                    </div>
                    {
                        this.props.userInfo && (
                        <div 
                            className="button-group" 
                            style={{
                                height: 25,
                                marginTop: 5,
                                marginLeft: 20, 
                                marginRight: 5, 
                                padding: 0
                            }}>
                            <div
                                key="save"
                                className={needUpload ? "" : "disabled"}
                                onClick={needUpload ? this.handleSaveFile : undefined}>
                                {generateIcon("assets/svg/toolbar-save.svg") }
                                <span>{formatMessage({id: "app.save"}) }</span>
                            </div> 
                            <div
                                key="saveAll"
                                className={needUpload ? "" : "disabled"}
                                onClick={needUpload ? this.handleSaveAllFile : undefined}>
                                {generateIcon("assets/svg/toolbar-save-all.svg") }
                                <span>{formatMessage({id: "app.saveAll"}) }</span>
                            </div> 
                        </div>
                        )
                    }
                </div>
            </div>
        )
    }
}
export default withRouter(connect(mapStateToProps, mapDispatchTpProps)(ToolPanel));